CREATE VIEW `ads_trade_sharpenginepaycenter_payorder_view` (`dt` COMMENT "createtime 分区", `product_id` COMMENT "充值产品编号", `id`, `order_serial_id` COMMENT "订单流水号全局唯一,写入到业务库使用", `order_id` COMMENT "订单号,透传给支付合作方", `coo_order_id` COMMENT "支付订单号,合作方回传的", `pay_chanel_id` COMMENT "渠道号", `account` COMMENT "账号", `user_id` COMMENT "用户Id", `server_id` COMMENT "服务器id,已废弃", `user_ip_address` COMMENT "客户端ip", `create_time` COMMENT "创建时间", `coo_notify_time` COMMENT "收到的付款时间", `finish_time` COMMENT "订单处理完成时间,表示已经发送给业务服务器的时间", `amount` COMMENT "金额,元为单位", `give_amount` COMMENT "赠送金额,一般无用了", `bank_amount` COMMENT "银行金额,一般等同于Amount", `order_status` COMMENT "订单状态1为成功", `coo_order_status` COMMENT "合作方扣款状态1为成功", `shop_item` COMMENT "支付的商品id", `pay_type`, `bank_id`, `Ext1`, `Ext2`, `Ext3`, `Ext4`, `Ext5`, `os_type` COMMENT "相当于Mt", `shop_item_id` COMMENT "商品Id,配置在后台", `coupon_id` COMMENT "优惠券Id", `package_id` COMMENT "客户端透传参数,不同场景用途不一样", `phone`, `has_notify_times`, `pay_config_id`, `core`, `base_amount` COMMENT "统计收入金额字段", `unique_guid`, `test_flag` COMMENT "测试标记1为测试", `coo_ext_status`, `coo_ext_info`, `bill_info`, `row_update_timestamp`, `sub_pay_type` COMMENT "子渠道类型", `AutoRenewTimes` COMMENT "续订次数", `uuid` COMMENT "支付链路串联唯一标识 类似tradeid", `etl_time` COMMENT "数据etl时间")
